217	   *
218	   * Find the first pending engine in any running rig whose upstream is
219	   * all completed. Execute it:
220	   * - Clockwork ('completed') → store yields, mark engine completed,
221	   *   check for rig completion.
222	   * - Quick ('launched') → store sessionId, mark engine running.
223	   */
224	  async function tryRun(): Promise<CrawlResult | null> {
225	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
226	    for (const rig of runningRigs) {
227	      const pending = findRunnableEngine(rig);
228	      if (!pending) continue;
229	
230	      const design = fabricator.getEngineDesign(pending.designId);
231	      if (!design) {
232	        await failEngine(rig, pending.id, `No engine design found for "${pending.designId}"`);
233	        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
234	      }
235	
236	      const now = new Date().toISOString();
237	      const upstream = buildUpstreamMap(rig);
238	      const givens = { ...pending.givensSpec };
239	      const context = { engineId: pending.id, upstream };
240	
241	      let engineResult: Awaited<ReturnType<typeof design.run>>;
242	      try {
243	        // Mark engine as running before executing
244	        const startedEngines = rig.engines.map((e) =>
245	          e.id === pending.id ? { ...e, status: 'running' as const, startedAt: now } : e,
246	        );
247	        await rigsBook.patch(rig.id, { engines: startedEngines });
248	
249	        // Re-fetch to get the up-to-date engines list (with startedAt set)
250	        const updatedRig = { ...rig, engines: startedEngines };
251	
252	        engineResult = await design.run(givens, context);
253	
254	        if (engineResult.status === 'launched') {
255	          // Quick engine — store sessionId, leave engine in 'running'
256	          const { sessionId } = engineResult;
257	          const launchedEngines = updatedRig.engines.map((e) =>
258	            e.id === pending.id
259	              ? { ...e, status: 'running' as const, sessionId }
260	              : e,
261	          );
262	          await rigsBook.patch(rig.id, { engines: launchedEngines });
263	          return { action: 'engine-started', rigId: rig.id, engineId: pending.id };
264	        }
265	
266	        // Clockwork engine — validate and store yields
267	        const { yields } = engineResult;
268	        if (!isJsonSerializable(yields)) {
269	          await failEngine(updatedRig, pending.id, 'Engine yields are not JSON-serializable');
270	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
271	        }
272	
273	        const completedAt = new Date().toISOString();
274	        const completedEngines = updatedRig.engines.map((e) =>
275	          e.id === pending.id
276	            ? { ...e, status: 'completed' as const, yields, completedAt }
277	            : e,
278	        );
279	        const allCompleted = completedEngines.every((e) => e.status === 'completed');
280	        await rigsBook.patch(rig.id, {
281	          engines: completedEngines,
282	          status: allCompleted ? 'completed' : 'running',
283	        });
284	
285	        if (allCompleted) {
286	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
287	        }
288	        return { action: 'engine-completed', rigId: rig.id, engineId: pending.id };
289	      } catch (err) {
290	        const errorMessage = err instanceof Error ? err.message : String(err);
291	        await failEngine(rig, pending.id, errorMessage);
292	        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
293	      }
294	    }
295	    return null;
296	  }
297	
298	  /**
299	   * Phase 3 — spawn.
300	   *
301	   * Find the oldest ready writ with no existing rig. Create a rig and
302	   * transition the writ to active so the Clerk tracks it as in-progress.
303	   */
304	  async function trySpawn(): Promise<CrawlResult | null> {
305	    // Find ready writs ordered by creation time (oldest first)
306	    const readyWrits = await writsBook.find({
307	      where: [['status', '=', 'ready']],
308	      orderBy: ['createdAt', 'asc'],
309	      limit: 10,
310	    });
311	
312	    for (const writ of readyWrits) {
313	      // Check for existing rig
314	      const existing = await rigsBook.find({
315	        where: [['writId', '=', writ.id]],
316	        limit: 1,
317	      });
318	      if (existing.length > 0) continue;
319	
320	      const rigId = generateId('rig', 4);
321	      const engines = buildStaticEngines(writ, spiderConfig);
322	
323	      const rig: RigDoc = {
324	        id: rigId,
325	        writId: writ.id,
326	        status: 'running',
327	        engines,
328	        createdAt: new Date().toISOString(),
329	      };
330	
331	      await rigsBook.put(rig);
332	
333	      // Transition writ to active so Clerk tracks it
334	      try {
335	        await clerk.transition(writ.id, 'active');
336	      } catch (err) {
337	        // Only swallow state-transition conflicts (writ already moved past 'ready')
338	        if (err instanceof Error && err.message.includes('transition')) {
339	          // Race condition — another spider got here first. The rig is already created,
340	          // so we continue. The writ is already active or beyond.
341	        } else {
342	          throw err;
343	        }
344	      }
345	
346	      return { action: 'rig-spawned', rigId, writId: writ.id };
347	    }
348	
349	    return null;
350	  }
351	
352	  // ── SpiderApi ─────────────────────────────────────────────────────
353	
354	  const api: SpiderApi = {
355	    async crawl(): Promise<CrawlResult | null> {
356	      const collected = await tryCollect();
357	      if (collected) return collected;
358	
359	      const ran = await tryRun();
360	      if (ran) return ran;
361	
362	      const spawned = await trySpawn();
363	      if (spawned) return spawned;
